// Import from '@/components/ui'

// Button
export type ButtonVariant = 'primary' | 'secondary' | 'outline' | 'ghost' | 'danger';
export type ButtonSize = 'sm' | 'md' | 'lg';
export interface ButtonProps extends PressableProps, AccessibilityProps {
  children: React.ReactNode;
  variant?: ButtonVariant;
  size?: ButtonSize;
  loading?: boolean;
  disabled?: boolean;
  style?: ViewStyle;
  textStyle?: TextStyle;
}

// Input
export interface InputProps extends TextInputProps {
  label?: string;
  error?: string;
  helperText?: string;
  disabled?: boolean;
  containerStyle?: ViewStyle;
  inputStyle?: TextStyle;
  labelStyle?: TextStyle;
}

// Card
export type CardPadding = 'none' | 'sm' | 'md' | 'lg';
export type CardElevation = 'none' | 'sm' | 'md' | 'lg';
export interface CardProps extends PressableProps {
  children: React.ReactNode;
  padding?: CardPadding;
  elevation?: CardElevation;
  pressable?: boolean;
  style?: ViewStyle;
  backgroundColor?: string;
}

// Text
export type TextVariant = 'body' | 'bodySmall' | 'caption' | 'heading' | 'headingSmall' | 'display' | 'label';
export type TextColor = 'default' | 'secondary' | 'muted' | 'primary' | 'error' | 'success' | 'warning';
export interface TextProps extends RNTextProps {
  variant?: TextVariant;
  color?: TextColor;
  bold?: boolean;
  center?: boolean;
  style?: TextStyle;
}

// Spinner
export type SpinnerSize = 'small' | 'large';
export interface SpinnerProps {
  size?: SpinnerSize;
  color?: string;
  message?: string;
  center?: boolean;
  fullScreen?: boolean;
  style?: ViewStyle;
}

// ColorPicker
export const PRESET_COLORS: readonly ['#EF4444', '#F97316', '#F59E0B', '#EAB308', '#84CC16', '#22C55E', '#14B8A6', '#06B6D4', '#3B82F6', '#6366F1', '#8B5CF6', '#EC4899'];
export interface ColorPickerProps {
  value: string;
  onChange: (color: string) => void;
  label?: string;
  showCustomInput?: boolean;
  error?: string;
  style?: ViewStyle;
}
